import React, { useState } from 'react';
import { View, Button, Alert } from 'react-native';
import { InAppPurchases } from 'react-native-in-app-purchase';
import { useEffect } from 'react-native';

const PaymentModule = () => {
  const [products, setProducts] = useState([]);

  useEffect(() => {
    const fetchProducts = async () => {
      const productIds = ['your_product_id1', 'your_product_id2'];
      try {
        const productInfo = await InAppPurchases.getProducts(productIds);
        setProducts(productInfo);
      } catch (error) {
        Alert.alert('Error', 'Could not fetch products. Please try again later.');
      }
    };

    fetchProducts();
  }, []);

  const purchaseProduct = async (productId) => {
    try {
      await InAppPurchases.purchaseProduct(productId);
      Alert.alert('Success', 'Purchase successful!');
    } catch (error) {
      Alert.alert('Error', 'Purchase failed. Please check your payment method and try again.');
    }
  };

  return (
    <View>
      {products.map((product) => (
        <Button key={product.productId} title={`Buy ${product.title}`} onPress={() => purchaseProduct(product.productId)} />
      ))}
    </View>
  );
};

export default PaymentModule;